UPDATE lwh_ai_processing_job
SET worker_id = #{workerId}, locked_until = #{lockedUntil}, version = version + 1
WHERE id = #{id}
  AND version = #{version}
  AND (locked_until IS NULL OR locked_until < CURRENT_TIMESTAMP)

UPDATE lwh_ai_processing_job
SET status = 'RUNNING', progress = 10, started_at = COALESCE(started_at, #{startedAt})
WHERE id = #{id}
